const tasks = $('Fetch Tasks').all().map(i => i.json);
const ideias = $('Fetch Ideias').all().map(i => i.json);
const memories = $('Fetch Vector Memory').all().map(i => i.json);
const currentDate = new Date().toISOString();

const tasksText = tasks.length > 0
  ? tasks.map(t => `- [${t.status || 'N/A'}][${t.type || 'N/A'}] ${t.title}: ${(t.description || 'Sem descricao').substring(0, 200)}`).join('\n')
  : 'Nenhuma tarefa recente.';

const ideiasText = ideias.length > 0
  ? ideias.map(i => `- [${i.status || 'N/A'}] ${i.title}: ${(i.description || 'Sem descricao').substring(0, 200)}`).join('\n')
  : 'Nenhuma ideia recente.';

const memoriesText = memories.length > 0
  ? memories.map(m => `- [${(m.created_at || '').substring(0, 10)}] ${m.content}`).join('\n')
  : 'Nenhuma memoria anterior do C-Suite.';

const context = `DATA DA ANALISE: ${currentDate}\n\n=== TAREFAS RECENTES (ultimos 7 dias) ===\n${tasksText}\n\n=== IDEIAS E BACKLOG (ultimos 30 dias) ===\n${ideiasText}\n\n=== MEMORIA DO C-SUITE (decisoes anteriores) ===\n${memoriesText}`;

return [{ json: { context, runTimestamp: currentDate } }];

