const embeddingResponse = $json;
const parseDecision = $('Parse CEO Decision').first().json;

const embeddingValues = embeddingResponse?.embedding?.values || [];

if (embeddingValues.length === 0) {
  throw new Error('Embedding vazio. Resposta da API: ' + JSON.stringify(embeddingResponse).substring(0, 300));
}

const embeddingStr = '[' + embeddingValues.join(',') + ']';

const content = 'C-Suite Meeting — ' + parseDecision.runTimestamp + '\n\nResumo Executivo: ' + parseDecision.summaryText + '\n\nDecisoes: ' + JSON.stringify(parseDecision.decisoes || []);

const metadata = {
  runTimestamp: parseDecision.runTimestamp,
  issueTitle: parseDecision.issueTitle,
  type: 'csuite_meeting',
  embeddingDimensions: embeddingValues.length
};

return [{ json: { content, metadata: JSON.stringify(metadata), embeddingStr } }];
